-- Seed Ruben's email signature for Quarter Mile, Inc.
-- org_id: 4ca12dff-97be-4472-8099-ab102a3af01a

DO $$
DECLARE
  ruben_uid uuid;
  org_id uuid := '4ca12dff-97be-4472-8099-ab102a3af01a';
BEGIN
  SELECT id INTO ruben_uid FROM auth.users WHERE email = 'ruben@quartermileinc.com' LIMIT 1;
  IF ruben_uid IS NULL THEN RETURN; END IF;

  INSERT INTO email_signatures (user_id, organization_id, body, is_html)
  VALUES (ruben_uid, org_id, $SIG$
<style>
@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700;900&display=swap');
.sw{padding:.5rem 0}
.sb{background:#fff;border:.5px solid #ddd;border-radius:8px;overflow:hidden;width:100%}
.sh{background:#000;padding:9px 50% 9px 16px;text-align:center}
.sh p{font-family:'Montserrat',sans-serif;font-size:10px;font-weight:700;color:#93ca3b;letter-spacing:.1em;text-transform:uppercase;margin:0}
.sbody{padding:14px 16px;display:flex;gap:18px;align-items:center}
.sn{font-family:'Montserrat',sans-serif;font-size:15px;font-weight:700;color:#000;margin:0 0 1px}
.st{font-family:'Montserrat',sans-serif;font-size:11px;font-weight:600;color:#93ca3b;text-transform:uppercase;letter-spacing:.08em;margin:0 0 7px}
.sd{width:30px;height:2px;background:#ee2b7b;margin:0 0 8px;border-radius:1px}
.sc{font-family:'Montserrat',sans-serif;font-size:11px;color:#555;margin:2px 0}
.sc a{color:#93ca3b;text-decoration:none;font-weight:600}
.sf{background:#f5f5f5;border-top:2px solid #93ca3b;padding:7px 16px 7px 24px;display:flex;align-items:center;justify-content:flex-start;flex-wrap:wrap}
.ss{font-family:'Montserrat',sans-serif;font-size:9px;font-weight:700;color:#666;letter-spacing:.08em;text-transform:uppercase}
.dot{width:5px;height:5px;border-radius:50%;background:#ee2b7b;margin:0 7px;flex-shrink:0}
</style>

<div class="sw">
<div class="sb">
  <div class="sh"><p>Brand Visibility Solutions</p></div>
  <div class="sbody">
    <img src="data:image/png;base64," style="flex-shrink:0;width:88px;object-fit:contain;display:block;" alt="QMI Stacked Logo">
    <div style="flex:1;">
      <p class="sn">Ruben Reyes</p>
      <p class="st">President</p>
      <div class="sd"></div>
      <p class="sc">P: (956) 722-7690 &nbsp;·&nbsp; M: (956) 236-4367</p>
      <p class="sc">6420 Polaris Dr. Ste 4, Laredo, Texas 78041</p>
      <p class="sc"><a href="https://www.QuarterMileInc.com">www.QuarterMileInc.com</a></p>
    </div>
  </div>
  <div class="sf">
    <span class="ss">Branding</span><div class="dot"></div>
    <span class="ss">Marketing</span><div class="dot"></div>
    <span class="ss">Printing</span><div class="dot"></div>
    <span class="ss">Signs</span><div class="dot"></div>
    <span class="ss">Fleet</span>
  </div>
</div>
</div>
$SIG$, true)
  ON CONFLICT (user_id, organization_id) DO UPDATE SET body = EXCLUDED.body, is_html = EXCLUDED.is_html;
END $$;
